// Parse AppSumo HTML to extract deals using String Splitting (Robust & No External Libs)
const item = items[0].json;
// Extract HTML from ScrapeOps response - try multiple formats
let html = '';

// ScrapeOps can return data in different formats
if (typeof item === 'string') {
  html = item;
} else if (item.response?.body) {
  html = item.response.body;
} else if (item.body) {
  html = item.body;
} else if (item.content) {
  html = item.content;
} else if (item.data) {
  html = item.data;
} else if (Array.isArray(item)) {
  // If it's an array, join it
  html = item.join('');
} else {
  // Last resort - stringify and check
  const str = JSON.stringify(item);
  if (str.includes('<!DOCTYPE') || str.includes('<html')) {
    html = str;
  }
}

const deals = [];

// Split by the deal container identified in the HTML
// Using a broader regex to catch variations in class spacing
const cardChunks = html.split(/class=["'][^"']*relative h-full[^"']*["']/i);

// Skip the first chunk (header/nav)
for (let i = 1; i < cardChunks.length; i++) {
  const card = cardChunks[i];

  // Extract Title and URL
  const urlMatch = card.match(/href=["'](\/products\/[^"']+)["']/i);
  const titleMatch = card.match(/<span class=["']sr-only["']>([^<]+)<\/span>/i);

  if (urlMatch && titleMatch) {
    const url = `https://appsumo.com${urlMatch[1]}`;
    const title = titleMatch[1];

    // Image
    const imgMatch = card.match(/<img[^>]+src=["']([^"']+)["']/i);
    const img = imgMatch ? imgMatch[1] : null;

    // Price
    const priceMatch = card.match(/id=["']deal-price["'][^>]*>([^<]+)</i);
    const currentPrice = priceMatch ? priceMatch[1].trim() : null;

    // Original Price
    const lastPriceMatch = card.match(/id=["']deal-price-original["'][^>]*>([^<]+)</i);
    const lastPrice = lastPriceMatch ? lastPriceMatch[1].trim() : null;

    // Discount Calculation
    let discount = null;
    if (currentPrice && lastPrice) {
        try {
            const curr = parseFloat(currentPrice.replace(/[^0-9.]/g, ''));
            const last = parseFloat(lastPrice.replace(/[^0-9.]/g, ''));
            if (last > 0) {
                const off = Math.round(((last - curr) / last) * 100);
                discount = `${off}% Off`;
            }
        } catch (e) {}
    }

    // Category
    // HTML: in<!-- --> <a ...>Productivity</a>
    // Regex needs to be loose about spaces and attributes
    const catMatch = card.match(/in<!-- -->\s*<a[^>]*>([^<]+)<\/a>/i);
    const category = catMatch ? catMatch[1].trim() : null;

    // Rating
    const ratingMatch = card.match(/alt=["']([0-9.]+)\s*stars["']/i);
    const rating = ratingMatch ? ratingMatch[1] : null;

    // Reviews
    // HTML: <span>92<!-- --> reviews</span>
    const reviewsMatch = card.match(/<span>(\d+)<!-- -->\s*reviews<\/span>/i);
    const reviewsCount = reviewsMatch ? reviewsMatch[1] : null;

    // Status
    let dealStatus = "Active";
    if (card.match(/Deal ends in/i)) dealStatus = "Ending Soon";
    if (card.match(/Sold Out/i)) dealStatus = "Sold Out";
    if (card.match(/Expired/i)) dealStatus = "Expired";

    deals.push({
      "Product Name": title,
      "AppSumo URL": url,
      "Category": category,
      "Current Price": currentPrice,
      "Last Price": lastPrice,
      "Discount": discount,
      "Deal Status": dealStatus,
      "Rating": rating,
      "Reviews Count": reviewsCount,
      "Image": img,
      "scraped_at": new Date().toISOString()
    });
  }
}

if (deals.length === 0) {
  return [{
    json: {
      "Debug": "No deals found",
      "HTML Length": html ? html.length : 0,
      "Input Keys": Object.keys(item),
      "HTML Preview": html ? html.substring(0, 500) : "No HTML found",
      "Split Chunks": cardChunks.length,
      "Item Type": typeof item,
      "Is Array": Array.isArray(item)
    }
  }];
}

return deals.map(deal => ({ json: deal }));

// Prepare New Deal - Process ALL items
const output = [];

for (const item of items) {
  output.push({
    json: {
      ...item.json,
      'Last Checked': new Date().toISOString()
    }
  });
}

return output;

// Compare Existing Deal - Process ALL items
const output = [];

for (const item of items) {
  // Just update timestamp
  output.push({
    json: {
      ...item.json,
      'Last Checked': new Date().toISOString()
    }
  });
}

return output;

// Filter for specific categories
const targetCategories = ['No-Code', 'Automation', 'AI', 'Productivity', 'Marketing'];

return items.filter(item => {
  const category = item.json['Category'] || '';
  const title = item.json['Product Name'] || '';

  // Check if any target category is mentioned in tags or title
  const isRelevant = targetCategories.some(cat => 
    category.toLowerCase().includes(cat.toLowerCase()) || 
    title.toLowerCase().includes(cat.toLowerCase())
  );

  return isRelevant;
});
